class Solution:
    def dfs(self, node, visited, graph, low, disc):
        if not visited[node]:
            disc[node] = low[node] = self.time = self.time + 1
            for neighbor in graph[node]:
                if not visited[neighbor]:
                    low[neighbor] = disc[node]
            for neighbor in graph[node]:
                if not visited[neighbor]:
                    disc[neighbor] = self.dfs(neighbor, visited, graph, low, disc)
            return disc[node]

    def topologicalSort(self, graph):
        n = len(graph)
        low = [0] * n
        disc = [0] * n
        visited = [False] * n

        for i in range(n):
            if not visited[i]:
                self.dfs(i, visited, graph, low, disc)

        order = [
            for i in range(n-1, -1, -1)
            if not visited[i]
            ]

        order.sort(key=lambda x: graph[x][0], reverse=True)

        return order


