// Complete the Solution class with the following code
#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

class Solution {
public:
    vector<int> topologicalSort(vector<vector<int>>& graph) {
        int n = graph.size();
        int[] low = new int[n];
        int[] disc = new int[n];
        bool[] visited = new boolean[n];
        int time = 0;

        for (int i = 0; i < n; i++) {
            if (!visited[i]) {
                dfs(i, low, disc, visited, graph);
            }
        }

        vector<int> order;
        for (int i = n - 1; i >= 0; i--) {
            if (!visited[i]) {
                order.push_back(i);
            }
        }

        // Sort the order in reverse
        sort(order.begin(), order.end(), [](int a, int b) {
            return graph[a][0] < graph[b][0];
        });

        return order;

        // Helper function to perform DFS
        void dfs(int node, int[] low, int[] disc, bool[] visited, vector<vector<int>>& graph) {
            if (!visited[node]) {
                disc[node] = low[node] = ++time;
                for (int neighbor : graph[node]) {
                    if (!visited[neighbor]) {
                        low[neighbor] = disc[node];
                    }
                }
                for (int neighbor : graph[node]) {
                    if (!visited[neighbor]) {
                        disc[neighbor] = dfs(neighbor, low, disc, visited, graph);
                    }
                }
            }
            return disc[node];
        }
    }
};

int main() {
    int n;
    cout << "Enter number of nodes: ";
    cin >> n;
    vector<vector<int>> graph(n);
    for (int i = 0; i < n; i++) {
        int m;
        cout << "Enter number of edges for node " << i << ": ";
        cin >> m;
        for (int j = 0; j < m; j++) {
            int v;
            cout << "Enter edge for node " << i << ": ";
            cin >> v;
            graph[i].push_back(v);
        }
    }
    Solution s;
    vector<int> order = s.topologicalSort(graph);
    cout << "Topological sort: " << endl;
    for (int i = 0; i < order.size(); i++) {
        cout << order[i] << endl;
    }
    return 0;
}
